// // This module is a 4-bit down counter that decrements its value on every clock pulse and resets to zero when the reset signal is activated.
module counter_4bit (
    input clk,
    input reset,
    output reg [3:0] count
);

always @(posedge clk or posedge reset) begin
    if (reset) begin
        count <= 4'b0000;
    end else begin
        count <= count + 1;
    end
end

endmodule
